-- Table structure for table `mob_reward`
--

CREATE TABLE `mob_reward` (
  `id` int NOT NULL,
  `mob_id` int DEFAULT '-1' COMMENT 'ID quái (-1: tất cả quái)',
  `map_id` int DEFAULT '-1' COMMENT 'ID Map (-1: tất cả map)',
  `item_template_id` int NOT NULL COMMENT 'ID Item Template',
  `rate` int NOT NULL DEFAULT '100' COMMENT 'Tỉ lệ rơi (1/rate). VD: 100 = 1%',
  `quantity_min` int DEFAULT '1' COMMENT 'Số lượng tối thiểu',
  `quantity_max` int DEFAULT '1' COMMENT 'Số lượng tối đa',
  `gender` int DEFAULT '-1' COMMENT 'Giới tính (-1: all, 0: TDS, 1: Namếc, 2: Xayda)',
  `event_key` varchar(50) DEFAULT NULL COMMENT 'Tên sự kiện (CHRISTMAS, HALLOWEEN...). NULL = drop thường',
  `map_type` varchar(50) DEFAULT NULL COMMENT 'Loại map đặc biệt (MAP_COLD, MAP_SKH, MAP_PORATA...)',
  `options_json` text COMMENT 'JSON mảng options [{id:30,param:0}]',
  `condition_type` varchar(50) DEFAULT NULL COMMENT 'Điều kiện đặc biệt (FULL_SET_THAN, IS_BUMA, USE_MAYDO...)',
  `is_random_range` tinyint(1) DEFAULT '0' COMMENT '1: Random item từ item_template_id đến item_template_id + random_range',
  `random_range` int DEFAULT '0' COMMENT 'Phạm vi random item id',
  `notify_global` tinyint(1) DEFAULT '0' COMMENT '1: Thông báo toàn server khi rơi',
  `description` varchar(255) DEFAULT NULL COMMENT 'Mô tả cho dễ quản lý',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '1: Đang hoạt động, 0: Tắt'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

