INSERT INTO `notify` (`id`, `name`, `text`) VALUES
(1, 'Hỗ trợ nhiệm vụ', '1) Hỗ trợ nhiệm vụ TĐST:\r\nNgày thứ 2-3-4 trong tuần từ 5h\r\nđến 7h và từ 17h đến hết 19h,\r\nchỉ những cư dân đang làm nhiệm\r\nvụ này mới vào được map có boss,\r\nnày xuất hiện.\r\n(Núi khỉ đen, hang khỉ đen, núi khỉ\r\nđỏ).\r\n\r\n2) Hỗ trợ nhiệm vụ Xên Bọ Hung:\r\nNgày thứ 2-3-4 trong tuần, từ 2 giờ\r\nsáng đén hết 4 giờ sáng và từ 2 giờ\r\nchiều đến hết 4 giờ chiều, chỉ\r\nnhững cư dân đang làm nhiệm vụ\r\nnày mới vào được map có boss này\r\nxuất hiện.\r\n(Thị trấn Ginder, Võ đài Xên bọ\r\nhung).'),
(2, 'Cơ chế game', 'Nro Đai Chiến (test)\n \nTính Năng & Cơ Chế Game\nDame gốc, cày cuốc vàng, farm quái, săn boss\nTích hợp 3 mod APK, hỗ trợ PC và TF cho iPhone\nCode sự kiện: daichien1-5\n\nHệ Thống Trang Bị & Cày Cuốc\nTrang bị Max 8 SPL, ngọc xanh miễn phí nhận vô hạn\nSét kích hoạt: 3 món Thần Linh có thể hợp thành 1 món ngẫu nhiên (từ Vải Thô đến Thần Linh)\nThỏi vàng kiếm được qua farm quái, săn boss, giải Siêu Hang, Top săn boss hàng ngày\n\n? Tính Năng Bang Hội\n? Bang hội có thể nâng cấp để tăng chỉ số và mở thêm nhiều chức năng đặc biệt\nHệ Thống Đệ Tử\nCó 3 loại: Thường, Bư, Vip (Đệ tử VIP có bùa riêng)\nĐệ tử có thể nâng cấp tối đa cấp 10\n\nCác Hoạt Động & Tính Năng Đặc Biệt\nĐầy đủ: Đại Hội Võ Học (DHVH), Chiến Đấu Rực Lửa (CDRD), Bàn Đấu Kinh Bang (BDKB), Ngũ Hành Sơn\n\nLiên hệ & Thông tin\n Box Zalo: \n Website: nrodaichien.site'),
(3, 'Đua top ', 'Đua top sm và nạp xem tại npc OG73(19h8/3-19h14/3)\n\nPhần thưởng Đua Top Sức Đánh (SD)\n TOP 1:\n\n 1.500 thỏi vàng\n 50 mảnh CT\n 20 NRO 3 sao\n \n TOP 2:\n\n 1.000 thỏi vàng\n 30 mảnh CT\n15 NRO 3 sao\n\n TOP 3:\n\n500 thỏi vàng\n 20 mảnh CT\n 10 NRO 3 sao');
